sys_script_include.script:
var CG_InventoryCollector = Class.create();
CG_InventoryCollector.prototype = {

    initialize: function() {
        this.EXCLUDED_SCOPES = gs.getProperty('cg.excluded_scopes', '');
        this.INVENTORY_TABLE = 'u_cg_inventory';
        this.DAYS_TO_REMOVE = parseInt(gs.getProperty('cg.days_inactive_threshold', '180'));
        this.OOB_MODIFIED_CATEGORIES = [
            'Business Rule', 'Client Script', 'UI Policy',
            'ACL', 'Notification', 'UI Action', 'Inbound Action',
            'Scheduled Job', 'Script Include'
        ];
        this.results = {
            collected: 0,
            errors: []
        };
    },

    // =============================================
    // CLASSIFICAÇÃO DE STATUS
    // =============================================

    _classifyStatus: function(data) {
        var isActive = (data.active == 'true' || data.active === true || data.active == '1');
        var scope = (data.scope || '').toLowerCase();
        var category = data.category || '';
        var updatedOn = data.updated_on || '';

        // Regra 1: inativo há mais de DAYS_TO_REMOVE dias → to_remove
        if (!isActive && updatedOn) {
            var lastUpdate = new GlideDateTime(updatedOn);
            var now = new GlideDateTime();
            var msPerDay = 1000 * 60 * 60 * 24;
            var diffMs = now.getNumericValue() - lastUpdate.getNumericValue();
            var diffDays = Math.floor(diffMs / msPerDay);

            if (diffDays >= this.DAYS_TO_REMOVE) {
                return {
                    status: 'to_remove',
                    note: '[AUTO] Inativo há ' + diffDays + ' dias. Último update: ' +
                          updatedOn + ' por ' + (data.updated_by || 'desconhecido') +
                          '. Candidato à remoção (threshold: ' + this.DAYS_TO_REMOVE + ' dias).'
                };
            }
        }

        // Regra 2: escopo global + categoria crítica → oob_modified
        if (scope === 'global') {
            var isOobCategory = false;
            for (var i = 0; i < this.OOB_MODIFIED_CATEGORIES.length; i++) {
                if (this.OOB_MODIFIED_CATEGORIES[i] === category) {
                    isOobCategory = true;
                    break;
                }
            }
            if (isOobCategory) {
                return {
                    status: 'oob_modified',
                    note: '[AUTO] Artefato OOB modificado. Categoria: ' + category +
                          '. Escopo: Global. Revisar necessidade de manter customização.'
                };
            }
        }

        // Regra 3: padrão → active
        return { status: 'active', note: '' };
    },

    // =============================================
    // JOB DE CLASSIFICAÇÃO (registros existentes)
    // =============================================

    runClassification: function() {
        var classified = 0;
        var errors = 0;

        var inv = new GlideRecord(this.INVENTORY_TABLE);
        inv.query();

        while (inv.next()) {
            try {
                // Não sobrescreve justified (proteção futura)
                if (inv.getValue('u_status') === 'justified') continue;

                var data = {
                    active: inv.getValue('u_active'),
                    scope: inv.getValue('u_scope'),
                    category: inv.getValue('u_category'),
                    updated_on: inv.getValue('u_last_updated_on'),
                    updated_by: inv.getValue('u_last_updated_by')
                };

                var classification = this._classifyStatus(data);

                inv.setValue('u_status', classification.status);
                // Atualiza note sempre — limpa se não há nota nova
                if (classification.note) {
                    inv.setValue('u_notes', classification.note);
                } else {
                    inv.setValue('u_notes', '');
                }
                inv.update();
                classified++;

            } catch (e) {
                errors++;
                gs.warn('CG runClassification erro: ' + inv.getValue('u_name') + ' - ' + e.message);
            }
        }

        gs.info('CG runClassification: ' + classified + ' registros classificados. Erros: ' + errors);
        return { classified: classified, errors: errors };
    },

    // =============================================
    // COLETA COMPLETA
    // =============================================

    _addScopeExclusion: function(gr) {
        if (!this.EXCLUDED_SCOPES) return;
        var scopes = this.EXCLUDED_SCOPES.split(',');
        for (var i = 0; i < scopes.length; i++) {
            var scope = scopes[i].trim();
            if (scope) gr.addQuery('sys_scope', '!=', scope);
        }
    },

    _getUpdateSetInfo: function(sysId) {
        var result = { update_set: '', updated_on: '', updated_by: '' };
        try {
            var xml = new GlideRecord('sys_update_xml');
            xml.addQuery('name', 'CONTAINS', sysId);
            xml.orderByDesc('sys_updated_on');
            xml.setLimit(1);
            xml.query();
            if (xml.next()) {
                result.update_set = xml.getDisplayValue('update_set');
                result.updated_on = xml.getValue('sys_updated_on');
                result.updated_by = xml.getValue('sys_updated_by');
            }
        } catch (e) {
            gs.warn('CG_InventoryCollector: erro ao buscar update set para ' + sysId);
        }
        return result;
    },

    runFullInventory: function() {
        this._collectCustomTables();
        this._collectCustomFields();
        this._collectBusinessRules();
        this._collectClientScripts();
        this._collectUIPolicies();
        this._collectUIActions();
        this._collectScriptIncludes();
        this._collectScheduledJobs();
        this._collectFlows();
        this._collectRecordProducers();
        this._collectNotifications();
        this._collectInboundActions();
        this._collectSLAs();
        this._collectACLs();
        this._collectReports();
        this._collectSPWidgets();
        this._collectCustomRoles();
        this._collectTransformMaps();
        this._collectDataSources();
        this._collectCatalogItems();
        this._collectUIPages();
        this._collectFlowActions();
        this._collectScopedApps();

        gs.info('CG_InventoryCollector: coleta concluida. Total: ' +
            this.results.collected + ' artefatos. Erros: ' + this.results.errors.length);
        return this.results;
    },

    _collectCustomTables: function() {
        var gr = new GlideRecord('sys_db_object');
        gr.addQuery('sys_update_name', 'ISNOTEMPTY', '');
        gr.addQuery('name', 'STARTSWITH', 'u_').addOrCondition('name', 'STARTSWITH', 'x_');
        this._addScopeExclusion(gr);
        gr.query();
        while (gr.next()) {
            if (!global.SncAppFiles.hasCustomerUpdate(gr)) continue;
            var us = this._getUpdateSetInfo(gr.getValue('sys_id'));
            this._saveRecord({ category: 'Custom Table', name: gr.getValue('name'), label: gr.getDisplayValue('label'), scope: gr.getDisplayValue('sys_scope'), sys_id: gr.getValue('sys_id'), active: 'true', update_set: us.update_set, updated_on: us.updated_on, updated_by: us.updated_by });
        }
    },

    _collectCustomFields: function() {
        var gr = new GlideRecord('sys_dictionary');
        gr.addQuery('sys_update_name', 'ISNOTEMPTY', '');
        gr.addQuery('element', 'STARTSWITH', 'u_');
        gr.addQuery('internal_type', '!=', 'collection');
        this._addScopeExclusion(gr);
        gr.query();
        while (gr.next()) {
            if (!global.SncAppFiles.hasCustomerUpdate(gr)) continue;
            var us = this._getUpdateSetInfo(gr.getValue('sys_id'));
            this._saveRecord({ category: 'Custom Field', name: gr.getValue('element'), label: gr.getDisplayValue('column_label'), scope: gr.getDisplayValue('sys_scope'), sys_id: gr.getValue('sys_id'), table_name: gr.getValue('name'), active: 'true', update_set: us.update_set, updated_on: us.updated_on, updated_by: us.updated_by });
        }
    },

